VALUES
  ('disabled-6f0ba476-moex-00051', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司於 X5 年初開始興建廠房，於 X5 年 1 月 2 日及 9 月 1 日分別投入 工程支出$1,600,000及$4,800,000。該公司於X5年初向銀行取得興建廠房 專案借款$6,400,000，專案借款利率為10%，未動用借款有存款利息4%。 若X5年底該廠房未興建完成，則X5年底該興建中廠房之成本為何？', '["$6,400,000", "$6,912,000", "$6,976,000", "$7,040,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "6a35de923302", "answer_pdf_sha1": "643ffd8ef1e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00052', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲牧場於X5年底買入500頭肉牛，每頭價格為$18,000，另支付運輸費用 $80,000 及其他交易成本$20,000，估計將牛隻立即於市場出售，應支付運 輸費用$84,000 及出售成本$30,000。試問購入 500 頭肉牛對 X5 年稅前淨 利之影響為何？', '["無影響", "減少$50,000", "減少$114,000", "減少$214,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "6a35de923302", "answer_pdf_sha1": "643ffd8ef1e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00053', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司於X5年1月1日開始承租一台機器，租期5年，每年1月1日須 支付租金$550,000，租期屆滿須保證該機器值$1,500,000，惟甲公司預期租 期屆滿機器公允價值為$1,400,000。若甲公司的增額借款利率為 10%，並 知道租賃隱含利率為8%，則甲公司應認列之使用權資產成本為何？ （p =0.73503，P =3.31213；p =0.68301，P =3.16987； 4,8% 4,8% 4,10% 4,10% p =0.68058，P =3.99271；p =0.62092，P =3.79079） 5,8% 5,8% 5,10% 5,10%', '["$2,371,670", "$2,439,728", "$3,162,716", "$5,764,214"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "6a35de923302", "answer_pdf_sha1": "643ffd8ef1e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00054', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司 X5 年初有一票面利率 10%，有效利率 8%，每年 6 月 30 日及 12 月31日付息之應付公司債流通在外。若X5年12月31日付息分錄中含「 利息費用」$108,110及「公司債溢價」$16,890，則該應付公司債X5年12 月31日帳面金額應為何？', '["$2,500,000", "$2,685,860", "$2,702,750", "$2,803,600"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "6a35de923302", "answer_pdf_sha1": "643ffd8ef1e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00055', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司持有一面額$5,000,000，票面利率 4%，每年 6 月 30 日及 12 月 31 日付息之公司債，有效利率 5%，該債券投資符合分類為透過其他綜合損 益按公允價值衡量。X5年底該債券投資總帳面金額為$4,950,000，公允價 值為$4,926,000。若 X6 年 3 月 31 日甲公司以$4,918,000 加計應計利息出 售，另支付手續費$10,000，則甲公司應認列處分債券投資損益為何？（假 設不考慮預期信用損失）', '["處分損失$10,000", "處分損失$43,875", "處分損失$53,875", "處分損失$103,875"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "6a35de923302", "answer_pdf_sha1": "643ffd8ef1e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00056', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司 X5 年有關退休金資料如下：當期服務成本為$337,500，因精算假 設變動使確定福利義務現值減少$285,000，X5年底提撥退休基金$372,000 ，計畫資產實際報酬為$204,000，並支付退休金$321,000。若折現率為5% ，X5 年期初計畫資產公允價值為$1,800,000，確定福利義務現值為 $2,250,000，則X5年底資產負債表應報導之退休金負債為何？', '["$39,000", "$210,000", "$324,000", "$609,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "6a35de923302", "answer_pdf_sha1": "643ffd8ef1e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00057', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司於X5年成立，X7年中發現下列二項錯誤：', '["X5 年及 X6 年分別誤將承銷他公司之商品$190,000 及$590,000 計入期 末存貨中", "提供產品製造瑕疵的保固服務均於實際發生維修時認列維修支出，估計 X5年及X6年年底應報導保固負債準備分別為$154,000及$454,000。 若X6年底甲公司原報導權益總額為$5,634,000，負債比率為40%，則X6年 底正確負債比率為多少？（四捨五入到小數點後第二位，不考慮所得稅影響）", "45%", "46%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "6a35de923302", "answer_pdf_sha1": "643ffd8ef1e2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "1002", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00058', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'essay', '甲將 A 地借貸予乙使用，乙在該地上興建未辦理保存登記之違章建
築 B 屋一棟，並將該屋出租予丙。試問：倘丙租期屆滿不返還 B 屋，
乙能否主張依據所有物返還請求權之適用或類推適用，請求丙返還
該屋？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "803f0c4dbb29", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00059', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'essay', '甲承攬乙定作之興建 A 屋工作，其後因可歸責於承攬人甲之事由而
遲延完工，定作人乙乃依約計罰甲違約金新臺幣（下同）5,000 萬
元，並且自甲原有之承攬工程尾款 5,000 萬元中扣抵。甲不服，以
違約金過高為由，訴請法院酌減違約金，法院於 108 年底判決確定
酌減系爭違約金為 2,000 萬元。嗣甲於 113 年間請求乙返還該法院
核減後過高之違約金 3,000 萬元，乙主張甲之請求權已罹於時效而
消滅，試問何人之主張有理由？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "803f0c4dbb29", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00060', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '下列何者為不動產？', '["高雄輕軌電車之軌道", "建設公司為促銷預售屋，蓋在建築預定地上之樣品屋", "地震後，為讓受災戶等待房屋修復時所暫住之組合屋", "拍攝戲劇時，為搬運器材臨時所設之輕便軌道"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "803f0c4dbb29", "answer_pdf_sha1": "6d94596821bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL)
